import { isObject, isUndefined } from 'lodash-es';

import { _accessValue as accessValue } from '@dynatrace/strato-components/core';

const NESTED_LEVELS_SUPPORTED = 2;

const buildColumnsHeadersMapping = (columns: Set<string>) =>
  new Map([...columns].map((value, index) => [value, index]));

const getObjectHeaders = (
  data: Record<string, unknown>[],
  objectKey = '',
  nestingLevel = 0,
) => {
  let columnHeaders: string[] = [];

  if (nestingLevel <= NESTED_LEVELS_SUPPORTED) {
    for (let i = 0; i < data.length; i++) {
      for (const [key, value] of Object.entries(data[i])) {
        const objectPath = [objectKey, key].filter((a) => a).join('.');
        if (!isObject(value)) {
          columnHeaders.push(objectPath);
        } else if (!Array.isArray(value)) {
          const headers = getObjectHeaders(
            [value as Record<string, unknown>],
            objectPath,
            nestingLevel + 1,
          );
          columnHeaders = columnHeaders.concat(headers);
        }
      }
    }
  }
  return columnHeaders;
};

/**
 * Returns a set of object keys as column headers
 *
 * @param data - layers data
 */
export const getColumnHeaders = (
  data: Record<string, unknown>[],
): Set<string> => {
  const objectColumnHeaders = getObjectHeaders(data);
  const columnHeadersSet = new Set(objectColumnHeaders);
  const sortedHeaders = ['layer-name', 'latitude', 'longitude'];
  const startingHeaders = sortedHeaders.reduce(
    (headersList: string[], column) => {
      if (columnHeadersSet.has(column)) {
        headersList.push(column);
      }
      return headersList;
    },
    [],
  );

  return new Set([...startingHeaders, ...objectColumnHeaders]);
};

/**
 * Creates a tabular representation of the layer's data
 *
 * @param data - layers data
 */
export const tabularizeLayersData = (data: Record<string, unknown>[]) => {
  let csv = '';

  if (data.length > 0) {
    const columnHeaders = getColumnHeaders(data);
    csv += `${[...columnHeaders].join(',')}\n`;

    const columnCount = columnHeaders.size;
    const headersMapping = buildColumnsHeadersMapping(columnHeaders);

    for (const datum of data) {
      const row: unknown[] = [];
      row.length = columnCount;
      for (const [column, index] of headersMapping) {
        let value = accessValue(datum, column);
        if (!isUndefined(value)) {
          if (typeof value === 'string' && value.includes(',')) {
            value = `"${value}"`;
          }
          row[index] = value;
        }
      }
      csv += `${row.join(',')}\n`;
    }
  }

  return csv;
};
